import { Navigate } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { authService } from '../services/authService';

export default function AdminRoute({ children }) {
  const { isAuthenticated, user, token } = useAuth();
  const [isChecking, setIsChecking] = useState(true);
  const [currentUser, setCurrentUser] = useState(user);

  // Use user from context immediately, don't make API call that might fail
  useEffect(() => {
    // Set user from context immediately
    if (user) {
      setCurrentUser(user);
      setIsChecking(false);
      return;
    }

    // Only check if we have token but no user (shouldn't happen after login)
    if (isAuthenticated && token && !user) {
      const checkUserRole = async () => {
        try {
          const response = await authService.getUserProfile();
          console.log('User profile from backend:', response.user);
          console.log('User role:', response.user?.role);
          setCurrentUser(response.user);
        } catch (error) {
          console.error('Failed to fetch user profile:', error);
          // Don't clear auth on error, just use what we have
        } finally {
          setIsChecking(false);
        }
      };
      checkUserRole();
    } else {
      setIsChecking(false);
    }
  }, [isAuthenticated, token, user]);

  if (isChecking) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-white">
        <div className="text-center">
          <svg className="animate-spin h-12 w-12 text-sky-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="mt-4 text-gray-600">Checking permissions...</p>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  // Use currentUser (from backend) or fallback to user (from context)
  const userRole = currentUser?.role || user?.role;
  
  console.log('AdminRoute Check:', {
    isAuthenticated,
    userRole,
    userRoleType: typeof userRole,
    userRoleValue: JSON.stringify(userRole),
    currentUser,
    contextUser: user,
    token: token ? 'exists' : 'missing'
  });
  
  // Check if role is admin (case-insensitive and trim whitespace)
  const normalizedRole = String(userRole || '').toLowerCase().trim();
  
  if (normalizedRole !== 'admin') {
    console.error('❌ Admin access denied!', {
      detectedRole: userRole,
      normalizedRole: normalizedRole,
      expectedRole: 'admin',
      currentUser: JSON.stringify(currentUser),
      contextUser: JSON.stringify(user),
      currentUserRole: currentUser?.role,
      contextUserRole: user?.role
    });
    return <Navigate to="/dashboard" replace />;
  }

  console.log('✅ Admin access granted!', {
    role: userRole,
    user: currentUser || user
  });

  return children;
}
